// Conceptual structure of the new gateway
export function createGateway(config: GatewayConfig) {
  // 1. Initialize upstream MCP connections (one per tool the agent uses)
  const upstreams = config.tools.map(t => new UpstreamMCPClient(t.name, t.url));

  // 2. Create the gateway MCP server (what the agent connects to)
  const server = new McpServer({ name: 'layerinfinite-gateway', version: '2.0.0' });

  // 3. Intercept tools/list — enrich with historical scores
  server.tools.list = enrichToolList(upstreams, scoringEngine, config.mode);

  // 4. Intercept tools/call — optionally reroute, always capture outcome
  server.tools.call = interceptToolCall(upstreams, scoringEngine, policyEngine, config);

  // 5. Register internal-only tools (dashboard, admin — NOT agent-facing)
  registerAdminTools(server, config);

  return server;
}
