## 3. What's NEW

### 3.1 Gateway Proxy Logic (Core New Module)

```typescript
// packages/mcp-server/src/gateway/proxy.ts
//
// Intercepts tools/list and tools/call at the MCP protocol level.
// This is the heart of the V2 architecture.

async function handleToolsList(request, upstreamClients, scoringEngine, config) {
  // 1. Fetch real tool list from ALL upstream MCP servers in parallel
  const toolLists = await Promise.all(upstreamClients.map(c => c.listTools()));

  // 2. Flatten into a single tool list
  const allTools = toolLists.flat();

  // 3. For each tool, look up historical scores for the current task context
  const enrichedTools = await Promise.all(allTools.map(async (tool) => {
    const scores = await scoringEngine.getScores({
      action_name: tool.name,
      task: extractTaskFromContext(request),
      environment: config.environment,
    });
    // 4. Enrich the tool description
    return {
      ...tool,
      description: enrichDescription(tool.description, scores, config.mode),
    };
  }));

  return enrichedTools;
}

async function handleToolsCall(request, upstreamClients, scoringEngine, policyEngine, config) {
  const { toolName, params } = request;
  const mode = policyEngine.getMode(toolName, extractTaskFromContext(request));

  // 1. Resolve the upstream client for this tool
  const upstream = upstreamClients.find(c => c.hasTool(toolName));

  // 2. Mode-specific behavior
  switch (mode) {
    case 'shadow':
      // Pass through, capture outcome, but don't inject scores
      break;
    case 'recommend':
    case 'assist':
      // Tool description already enriched via tools/list — just execute
      break;
    case 'auto':
      // Check scores, possibly reroute to better tool
      const bestAction = await scoringEngine.getBestAction(toolName, context);
      if (bestAction && bestAction !== toolName) {
        toolName = bestAction;
        upstream = upstreamClients.find(c => c.hasTool(toolName));
      }
      break;
  }

  // 3. Execute on the real MCP server
  const startTime = Date.now();
  const result = await upstream.callTool(toolName, params);
  const latencyMs = Date.now() - startTime;

  // 4. Fire-and-forget: capture outcome async (agent doesn't wait)
  captureOutcomeAsync({
    toolName,
    params,
    result,
    latencyMs,
    decisionId: generateDecisionId(),
    episodeId: getOrCreateEpisode(request),
    environment: config.environment,
  });

  // 5. Return result to agent immediately
  return result;
}
```

### 3.2 Tool Description Enrichment Engine

