```typescript
// Generates enriched tool descriptions by merging historical scores
// into the plain tool description text.

function enrichDescription(
  originalDescription: string,
  scores: ToolScores | null,
  mode: 'shadow' | 'recommend' | 'assist' | 'auto'
): string {
  if (mode === 'shadow' || !scores) return originalDescription;
  if (mode === 'auto') return originalDescription; // agent shouldn't see scores in auto

  const prefix = mode === 'assist'
    ? `[LI: ${scores.successRate * 100}% success (n=${scores.totalRuns}), confidence ${scores.confidence}]`
    : `[LI: ${scores.successRate * 100}% success across ${scores.totalRuns} runs]`;

  return `${prefix} ${originalDescription}`;
}
```

