### 4.2 Entry Point and Boot Sequence

```typescript
// packages/mcp-server/src/index.ts — V2 rewrite
import { createGateway } from './gateway/proxy.js';
import { loadGatewayConfig } from './config.js';
import { UpstreamRegistry } from './gateway/upstream-registry.js';
import { ColdLog } from './db/cold-log.js';
import { FanOutWorker } from './db/fan-out-worker.js';

async function main() {
  // 1. Load config (upstream MCP servers, modes, thresholds)
  const config = loadGatewayConfig();

  // 2. Connect to upstream MCP servers
  const upstreams = new UpstreamRegistry(config.upstreamServers);
  await upstreams.connectAll();

  // 3. Initialize cold append-only log
  const coldLog = new ColdLog(config.coldLogPath);

  // 4. Start async fan-out worker (reads from cold log, updates warm/hot)
  const fanOut = new FanOutWorker(coldLog, config.liApi);
  fanOut.start(); // runs in background, never blocks

  // 5. Create and start gateway server
  const gateway = createGateway({ config, upstreams, coldLog, fanOut });

  // 6. Start HTTP server (or stdio transport for Claude Code)
  await gateway.listen({ port: config.port });
}

main();
