// packages/mcp-server/src/gateway/upstream-client.ts
// Each upstream MCP server gets its own client.

export class UpstreamMCPClient {
  private transport: StreamableHTTPClientTransport;

  constructor(private name: string, private url: string, private apiKey?: string) {
    this.transport = new StreamableHTTPClientTransport(
      new URL(this.url),
      { requestInit: { headers: apiKey ? { 'X-API-Key': apiKey } : {} } }
    );
  }

  async connect(): Promise<void> {
    this.client = new Client(
      { name: `li-gateway-${this.name}`, version: '2.0.0' },
      { capabilities: {} }
    );
    await this.client.connect(this.transport);
  }

  async listTools(): Promise<Tool[]> {
    const response = await this.client.listTools();
    // Tag each tool with its source server name
    return response.tools.map(t => ({ ...t, _source: this.name }));
  }

  async callTool(name: string, args: Record<string, unknown>): Promise<ToolResult> {
    const response = await this.client.callTool({ name, arguments: args });
    return response;
  }
}
