### 4.4 Async Fan-Out Worker

```typescript
// packages/mcp-server/src/db/fan-out-worker.ts
// Replaces outcome-orchestrator.ts.
// Reads from cold append-only log, fans out to warm/hot layers.

export class FanOutWorker {
  private running = false;

  start(): void {
    this.running = true;
    this.loop();
  }

  private async loop(): Promise<void> {
    while (this.running) {
      const batch = await this.coldLog.readUnprocessed(100);
      if (batch.length === 0) {
        await sleep(100); // no work, back off
        continue;
      }

      await Promise.all(batch.map(entry => this.processOne(entry)));
      await this.coldLog.markProcessed(batch.map(e => e.id));
    }
  }

  private async processOne(entry: ColdLogEntry): Promise<void> {
    // This replaces the 8 side-effects in outcome-orchestrator.ts
    await Promise.all([
      this.warmLayer.upsertScores(entry),       // PostgreSQL
      this.hotLayer.refresh(entry),              // Redis/LRU cache
      this.trustScore.update(entry),             // Trust scores
      this.driftDetector.check(entry),           // Drift detection
      this.sequenceTracker.update(entry),        // Episode tracking
      this.counterfactuals.write(entry),         // IPS engine
      this.rewardBackprop.process(entry),        // Reward propagation
      this.scoringInvalidator.invalidate(entry), // Cache invalidation
    ]);
  }
}
```

